				continue
			}
			dispatch.Assigns[i].GenRoute()
			newCost := dispatch.Assigns[i].Cost
			if newCost >= 0 && newCost-originalCosts[i] < bestCostDelta {
				bestCostDelta = newCost - originalCosts[i]
				bestAssignIdx = i
			}
			dispatch.Assigns[i].RemoveShip(shipID)
			dispatch.Assigns[i].GenRoute()
		}

		// Trial insert into a new empty assign slot
		if dispatch.AssignsLen < MAXASSIGNS {
			i := dispatch.AssignsLen
			originalCosts[i] = dispatch.Assigns[i].Cost
			ok := dispatch.Assigns[i].AddShip(shipID, ori, des)
			if ok {
				dispatch.Assigns[i].GenRoute()
				newCost := dispatch.Assigns[i].Cost
				if newCost >= 0 && newCost-originalCosts[i] < bestCostDelta {
					bestCostDelta = newCost - originalCosts[i]
					bestAssignIdx = i
				}
				dispatch.Assigns[i].RemoveShip(shipID)
				dispatch.Assigns[i].GenRoute()
			}
		}

		// Commit the best feasible insertion
		if bestAssignIdx >= 0 {
			dispatch.Assigns[bestAssignIdx].AddShip(shipID, ori, des)
			dispatch.Assigns[bestAssignIdx].GenRoute()
			if bestAssignIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen++
			}
		} else {
			// Fallback: force create a new assign for this order
			if dispatch.AssignsLen < MAXASSIGNS {
				dispatch.Assigns[dispatch.AssignsLen].AddShip(shipID, ori, des)
				dispatch.Assigns[dispatch.AssignsLen].GenRoute()
				dispatch.AssignsLen++
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

